SELECT qi.*, wo.product_name AS work_order_product_name
FROM quality_inspection qi
LEFT JOIN work_order wo ON qi.work_order_id = wo.id


        AND qi.work_order_id = #{workOrderId}


        AND qi.inspection_date >= #{startDate}


        AND qi.inspection_date <= #{endDate}


        AND qi.pass_rate >= #{minPassRate}


        AND qi.pass_rate <= #{maxPassRate}


ORDER BY qi.create_time DESC

mapper.update:
UPDATE quality_inspection
work_order_id = #{workOrderId}, inspection_date = #{inspectionDate}, inspector = #{inspector}, inspection_quantity = #{inspectionQuantity}, qualified_quantity = #{qualifiedQuantity}, unqualified_quantity = #{unqualifiedQuantity}, unqualified_reason = #{unqualifiedReason}, pass_rate = #{passRate},
WHERE id = #{id}
